#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int v;
    struct Node* next;
} Node;

typedef struct {
    Node** head;
    int n;
} Graph;

Graph* createGraph(int n) {
    Graph* g = (Graph*)malloc(sizeof(Graph));
    g->n = n;
    g->head = (Node**)calloc(n + 1, sizeof(Node*));
    return g;
}

void addEdge(Graph* g, int u, int v) {
    Node* a = (Node*)malloc(sizeof(Node)); a->v = v; a->next = g->head[u]; g->head[u] = a;
    Node* b = (Node*)malloc(sizeof(Node)); b->v = u; b->next = g->head[v]; g->head[v] = b;
}

void bfs(int start, Graph* g, int* farthest, int* maxDist) {
    int* dist = (int*)malloc((g->n + 1) * sizeof(int));
    for (int i = 1; i <= g->n; ++i) dist[i] = -1;
    int* q = (int*)malloc((g->n) * sizeof(int));
    int front = 0, back = 0;
    q[back++] = start;
    dist[start] = 0;
    *farthest = start;
    *maxDist = 0;
    while (front < back) {
        int u = q[front++];
        for (Node* cur = g->head[u]; cur; cur = cur->next) {
            int v = cur->v;
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q[back++] = v;
                if (dist[v] > *maxDist) {
                    *maxDist = dist[v];
                    *farthest = v;
                }
            }
        }
    }
    free(dist);
    free(q);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Graph* g = createGraph(N);
        for (int i = 0; i < N - 1; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            addEdge(g, u, v);
        }
        int far, d;
        bfs(1, g, &far, &d);
        bfs(far, g, &far, &d);
        printf("%d\n", d);
        // free graph
        for (int i = 1; i <= N; ++i) {
            Node* cur = g->head[i];
            while (cur) { Node* tmp = cur; cur = cur->next; free(tmp); }
        }
        free(g->head); free(g);
    }
    return 0;
}

