#include <bits/stdc++.h>
using namespace std;

pair<int,int> bfs(int start, const vector<vector<int>>& adj) {
    vector<int> dist(adj.size(), -1);
    queue<int> q;
    q.push(start);
    dist[start] = 0;
    int far = start, maxd = 0;
    while (!q.empty()) {
        int u = q.front(); q.pop();
        for (int v : adj[u]) {
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q.push(v);
                if (dist[v] > maxd) {
                    maxd = dist[v];
                    far = v;
                }
            }
        }
    }
    return {far, maxd};
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int N; cin >> N;
        vector<vector<int>> adj(N + 1);
        for (int i = 0; i < N - 1; ++i) {
            int u, v; cin >> u >> v;
            adj[u].push_back(v);
            adj[v].push_back(u);
        }
        auto p1 = bfs(1, adj);
        auto p2 = bfs(p1.first, adj);
        cout << p2.second << '\n';
    }
    return 0;
}

