let outputs = [];
function bfs(start, adj) {
  const n = adj.length;
  const dist = new Int32Array(n).fill(-1);
  const queue = new Int32Array(n);
  let head = 0, tail = 0;
  queue[tail++] = start;
  dist[start] = 0;
  let far = start, max = 0;
  while (head < tail) {
    const u = queue[head++];
    for (const v of adj[u]) {
      if (dist[v] === -1) {
        dist[v] = dist[u] + 1;
        queue[tail++] = v;
        if (dist[v] > max) { max = dist[v]; far = v; }
      }
    }
  }
  return [far, max];
}
for (let t = 0; t < T; ++t) {
